class A:
    def __init__(self):
        self.x = 1
class B(A):
    def __init__(self):
        super().__init__()
        self.y = 2
b = B()
print(b.x, b.y)

class A:
    def f(self): return 1
class B(A):
    def f(self): return super().f() + 10
print(B().f())

class A:
    def f(self): return 'A'
class B(A):
    def f(self): return 'B' + super().f()
class C(A):
    def f(self): return 'C' + super().f()
class D(B, C):
    def f(self): return 'D' + super().f()
print(D().f())

class A:
    @staticmethod
    def add(a, b): return a + b
print(A.add(2, 3))

class A:
    name = 'A'
    @classmethod
    def who(cls): return cls.name
class B(A):
    name = 'B'
print(A.who(), B.who())

class A:
    @classmethod
    def make(cls): return cls()
    def __init__(self): self.v = 7
print(A.make().v)

class A:
    def __init__(self, r): self._r = r
    @property
    def area(self): return self._r * self._r
print(A(4).area)

class A:
    def __init__(self): self._x = 0
    @property
    def x(self): return self._x
    @x.setter
    def x(self, v): self._x = v * 2
a = A()
a.x = 5
print(a.x)

class A:
    def __new__(cls):
        obj = super().__new__(cls)
        obj.tag = 'new'
        return obj
print(A().tag)

class A:
    def __repr__(self): return 'A!'
print(repr(A()), str(A()))

class A:
    def __str__(self): return 'as-str'
print(str(A()))

class A:
    def __repr__(self): return 'rep'
print([A(), A()])

class Box:
    def __init__(self, items): self.items = items
    def __len__(self): return len(self.items)
    def __getitem__(self, i): return self.items[i]
b = Box([10, 20, 30])
print(len(b), b[1])

class Box:
    def __contains__(self, x): return x == 42
print(42 in Box(), 1 in Box())

